 update sboard2 set BTITLE =
		#{btitle, jdbcType=VARCHAR}, BCONTENT = #{bcontent, jdbcType=VARCHAR},
		BFILE = #{bfile, jdbcType=VARCHAR} where id = #{id, jdbcType=INTEGER}
		and BPASS = #{bpass, jdbcType=VARCHAR}

mapper.select:
 select * from( select row_number() over(order by id desc)
		as rnum, id, app_user_id, btitle, bcontent, bpass, bfile, bip, bhit,
		created_at from sboard2) A where A.rnum between #{start} and #{end}

 select * from( select row_number() over(order by id desc)
		as rnum, id, app_user_id, btitle, bcontent, bpass, bfile, bip, bhit,
		created_at from sboard2   WHERE btitle LIKE '%' || #{search} || '%' ) A where A.rnum between #{start} and #{end}
